@prefix cdi: <http://ddialliance.org/Specification/DDI-CDI/1.0/RDF/> .
@prefix ns1: <https://ada.astromat.org/metadata/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode [ a cdi:TabularTextDataSet,
                        ns1:tabularData ;
                    cdi:isDelimited true ;
                    ns1:componentType [ a ns1:MCICPMSTabular ] ;
                    ns1:coordUnits "micrometer" ;
                    ns1:xCoordCol "X_um" ;
                    ns1:yCoordCol "Y_um" ] ;
            sh:resultMessage "A TabularTextDataSet should have physical mappings (cdi:hasPhysicalMapping) linking variables to columns." ;
            sh:resultPath cdi:hasPhysicalMapping ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "A TabularTextDataSet should have physical mappings (cdi:hasPhysicalMapping) linking variables to columns." ;
                    sh:minCount 1 ;
                    sh:path cdi:hasPhysicalMapping ;
                    sh:severity sh:Warning ] ] .

